class Solution {
    public Node constructBinaryTree(List<Integer> preorder, List<Integer> inorder) {
        int[] rootIdx = {0};  // Since Java doesn't have reference parameters, we use an array to mimic pass-by-reference
        return build(preorder, inorder, rootIdx, 0, inorder.size() - 1);
    }

    private Node build(List<Integer> preorder, List<Integer> inorder, int[] rootIdx, int left, int right) {
        if (left > right) return null;
        int pivot = left;

        // Find the root in the inorder list
        while (!inorder.get(pivot).equals(preorder.get(rootIdx[0]))) {
            pivot++;
        }

        rootIdx[0]++;
        Node newNode = new Node(inorder.get(pivot));
        newNode.left = build(preorder, inorder, rootIdx, left, pivot - 1);
        newNode.right = build(preorder, inorder, rootIdx, pivot + 1, right);

        return newNode;
    }
}

